import asyncio
import json
from flask import Flask, jsonify, request
from solana.rpc.async_api import AsyncClient
from solana.rpc.commitment import Commitment
from solana.rpc.types import TokenAccountOpts
from solders.pubkey import Pubkey
from solders.signature import Signature

app = Flask(__name__)

# Use devnet for now
DEVNET_URL = "https://api.devnet.solana.com"
client = AsyncClient(DEVNET_URL)

# Helper to run async functions
def run_async(coro):
    loop = asyncio.new_event_loop()
    asyncio.set_event_loop(loop)
    return loop.run_until_complete(coro)

@app.route('/status', methods=['GET'])
def status():
    try:
        version_resp = run_async(client.get_version())
        slot_resp = run_async(client.get_slot())
        # node count? not directly available; we can use get_cluster_nodes
        # but for simplicity we can set a placeholder
        network = "devnet"  # could detect from endpoint
        status_val = "online" if version_resp.value else "offline"
        return jsonify({
            "status": status_val,
            "network": network,
            "current_slot": slot_resp.value,
            "node_count": 1,  # placeholder
            "version": str(version_resp.value)
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/block/<int:slot_number>', methods=['GET'])
def block(slot_number):
    try:
        resp = run_async(client.get_block(slot_number))
        if resp.value is None:
            return jsonify({"error": "Block not found"}), 404
        block = resp.value
        return jsonify({
            "blockhash": str(block.blockhash) if block.blockhash else None,
            "parent_slot": block.parent_slot,
            "previous_blockhash": str(block.previous_blockhash) if block.previous_blockhash else None,
            "block_height": block.block_height,
            "block_time": block.block_time
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/transaction/<signature>', methods=['GET'])
def transaction(signature):
    try:
        sig = Signature.from_string(signature)
        resp = run_async(client.get_transaction(sig, encoding="jsonParsed", max_supported_transaction_version=0))
        if resp.value is None:
            return jsonify({"error": "Transaction not found"}), 404
        tx = resp.value
        meta = tx.transaction.meta
        slot = tx.slot
        block_time = tx.block_time
        success = meta.err is None
        fee = meta.fee
        # token transfers
        token_transfers = []
        if meta.pre_token_balances and meta.post_token_balances:
            # map by account index and mint
            pre_map = {}
            for bal in meta.pre_token_balances:
                key = (bal.account_index, str(bal.mint))
                pre_map[key] = bal.ui_token_amount.ui_amount or 0
            for bal in meta.post_token_balances:
                key = (bal.account_index, str(bal.mint))
                pre = pre_map.get(key, 0)
                post = bal.ui_token_amount.ui_amount or 0
                delta = post - pre
                if delta != 0:
                    # need account address from transaction message
                    # we can get account pubkey from tx.transaction.message.account_keys
                    account_keys = tx.transaction.message.account_keys
                    if bal.account_index < len(account_keys):
                        account = str(account_keys[bal.account_index])
                        token_transfers.append({
                            "account": account,
                            "mint": str(bal.mint),
                            "amount": delta
                        })
        return jsonify({
            "signature": signature,
            "slot": slot,
            "block_time": block_time,
            "success": success,
            "fee": fee,
            "token_transfers": token_transfers
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/account/<address>', methods=['GET'])
def account(address):
    try:
        pubkey = Pubkey.from_string(address)
        resp = run_async(client.get_account_info(pubkey))
        if resp.value is None:
            return jsonify({"error": "Account not found"}), 404
        acc = resp.value
        return jsonify({
            "address": address,
            "executable": acc.executable,
            "lamports": acc.lamports,
            "owner": str(acc.owner),
            "rent_epoch": acc.rent_epoch
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/program/<program_id>/accounts', methods=['GET'])
def program_accounts(program_id):
    try:
        prog = Pubkey.from_string(program_id)
        limit = int(request.args.get('limit', 10))
        offset = int(request.args.get('offset', 0))
        # get all accounts (could be heavy) but we'll fetch with pagination using get_program_accounts
        # with data slice maybe; but we'll just fetch all and slice (not efficient for large)
        # For demo we'll use get_program_accounts with limit and offset using config
        # solana-py doesn't support pagination; we'll fetch all and slice.
        resp = run_async(client.get_program_accounts(prog))
        accounts = resp.value
        total = len(accounts)
        # slice
        paginated = accounts[offset:offset+limit]
        result = []
        for acc in paginated:
            result.append({
                "pubkey": str(acc.pubkey),
                "account": {
                    "executable": acc.account.executable,
                    "lamports": acc.account.lamports,
                    "owner": str(acc.account.owner),
                    "rent_epoch": acc.account.rent_epoch
                }
            })
        return jsonify({
            "program_id": program_id,
            "total_accounts": total,
            "limit": limit,
            "offset": offset,
            "accounts": result
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)
